async (params, browser) => {
  // Open Airtable table
  await browser.open(`${params.table_url}`)

  // Wait for grid to load
  await browser.waitForSelector('.dataRow, [data-rowindex], .cell, .headerRow', 15000)

  // Let grid fully render
  await browser.wait(3000)

  // Extract column headers and row data
  const result = await browser.evaluate(`const headers = []; const headerEls = document.querySelectorAll('.headerRow .header, .columnHeader, [data-columnid] .header, [role="columnheader"]'); headerEls.forEach(h => { const text = h.textContent?.trim(); if (text && text.length > 0) headers.push(text); }); const rows = []; const rowEls = document.querySelectorAll('.dataRow, [data-rowindex], [role="row"]:not(.headerRow)'); for (let i = 0; i < Math.min(rowEls.length, 100); i++) { const row = rowEls[i]; const cells = row.querySelectorAll('.cell, [data-columnid], [role="gridcell"]'); const rowData = {}; cells.forEach((cell, idx) => { const key = headers[idx] || 'col_' + idx; const text = cell.textContent?.trim()?.substring(0, 300) || ''; if (text) rowData[key] = text; }); if (Object.keys(rowData).length > 0) rows.push(rowData); } return { headers: headers, row_count: rows.length, rows: rows }`)

  return result
}
